class Solution {
    public long minimumCost(String s) {
        int n = s.length();
        long res = Long.MAX_VALUE;
        long[] left = new long[n];
        long[] right = new long[n];

        // left[i] = cost to make s[0..i] all equal to s[i]
        for (int i = 1; i < n; ++i) {
            left[i] = left[i - 1];
            if (s.charAt(i) != s.charAt(i - 1)) {
                left[i] += i;
            }
        }

        // right[i] = cost to make s[i..n-1] all equal to s[i]
        for (int i = n - 2; i >= 0; --i) {
            right[i] = right[i + 1];
            if (s.charAt(i) != s.charAt(i + 1)) {
                right[i] += n - 1 - i;
            }
        }

        for (int i = 0; i < n; ++i) {
            res = Math.min(res, left[i] + right[i]);
        }

        return res;
    }
}
